import { AppShell } from "@/components/app-shell";
import { McpKeyPanel } from "@/components/mcp/mcp-key-panel";
import { McpActivationForm } from "@/components/mcp/mcp-activation-form";
import { getAuthContext } from "@/lib/firebase/auth";
import { skillsRepository } from "@/lib/repositories/skills-repository";

export default async function TeamPage() {
  const auth = await getAuthContext();
  if (!auth?.workspaceId) {
    return <AppShell title="Team"><p>Sessão não encontrada.</p></AppShell>;
  }

  const skills = await skillsRepository.list(auth.workspaceId);

  return (
    <AppShell title="Team">
      <div className="content-stack space-y-6">
        <section className="app-card">
          <h2 className="mb-2 font-semibold">Mapa de Skills do Time</h2>
          <p className="text-sm muted">Skills registradas no workspace: {skills.length}</p>
          <div className="quick-links mt-3">
            {skills.slice(0, 8).map((skill) => <span key={skill.id} className="tag-pill">{skill.name}</span>)}
          </div>
        </section>
        <section className="two-column">
          <div className="app-card"><McpKeyPanel /></div>
          <div className="app-card"><McpActivationForm /></div>
        </section>
      </div>
    </AppShell>
  );
}
